protected function detectCsvEncoding(mixed $resource): ?string
    {
        rewind($resource);

        $lineCount = 0;
        $contentSample = '';

        while ((! feof($resource)) && ($lineCount < 20)) {
            $line = fgets($resource);

            if ($line === false) {
                break;
            }

            $contentSample .= $line;
            $lineCount++;
        }

        // The encoding of a subset should be declared before the encoding of its superset.
        $encodings = [
            'UTF-8',
            'SJIS-win',
            'EUC-KR',
            'ISO-8859-1',
            'GB18030',
            'Windows-1251',
            'Windows-1252',
            'EUC-JP',
        ];

        foreach ($encodings as $encoding) {
            if (! mb_check_encoding($contentSample, $encoding)) {
                continue;
            }

            return $encoding;
        }

        return null;
    }

public function test_child_keys_in_a_sibling_loop_are_correctly_generated_when_the_parent_data_is_inserted()
    {
        app('livewire')->component('keys-parent-with-sibling-loops', KeysParentWithSiblingLoops::class);
        app('livewire')->component('keys-child', KeysChild::class);

        $component = Livewire::test(KeysParentWithSiblingLoops::class);

        $childrenBefore = invade($component)->lastState->getSnapshot()['memo']['children'];

        $component->call('insert');

        $childrenAfter = invade($component)->lastState->getSnapshot()['memo']['children'];

        $childKeys = array_keys(invade($component)->lastState->getSnapshot()['memo']['children']);

        $this->assertEquals(6, count($childKeys));

        $this->assertKeysMatchPattern([
            'lw-XXXXXXXX-0-0-B',
            'lw-XXXXXXXX-0-0-C',
            'lw-XXXXXXXX-0-0-D',
            'lw-XXXXXXXX-1-1-B',
            'lw-XXXXXXXX-1-1-C',
            'lw-XXXXXXXX-1-1-D',
        ], $childKeys);

        // Ensure that the children from before match the children after including ID and element...
        foreach ($childrenBefore as $key => $childBefore) {
            $this->assertEquals($childBefore, $childrenAfter[$key]);
        }
    }

public function test_a_second_inner_loop_is_added_when_the_first_inner_loop_is_closed()
    {
        SupportCompiledWireKeys::openLoop();
        SupportCompiledWireKeys::openLoop();
        SupportCompiledWireKeys::closeLoop();
        SupportCompiledWireKeys::openLoop();

        $this->assertEquals(
            [
                [
                    'count' => 0,
                    'index' => null,
                    'key' => null,
                ],
                [
                    'count' => 1,
                    'index' => null,
                    'key' => null,
                ],
            ],
            SupportCompiledWireKeys::$loopStack
        );

        $this->assertEquals(
            [
                'count' => null,
                'index' => null,
                'key' => null,
            ],
            SupportCompiledWireKeys::$currentLoop
        );
    }

public function test_lazy_requests_are_isolated_by_default()
    {
        Livewire::visit([new class extends Component {
            public function render() { return <<<HTML
            <div>
                <livewire:child num="1" />
                <livewire:child num="2" />
                <livewire:child num="3" />
            </div>
            HTML; }
        }, 'child' => new #[\Livewire\Attributes\Lazy] class extends Component {
            public $num;
            public $time;
            public function mount() {
                $this->time = LARAVEL_START;
            }
            public function render() { return <<<'HTML'
            <div id="child">
                Child {{ $num }}

                <span dusk="time-{{ $num }}">{{ $time }}</span>
            </div>
            HTML; }
        }])
        ->waitForText('Child 1')
        ->waitForText('Child 2')
        ->waitForText('Child 3')
        ->tap(function ($b) {
            $time1 = (float) $b->text('@time-1');
            $time2 = (float) $b->text('@time-2');
            $time3 = (float) $b->text('@time-3');

            $this->assertNotEquals($time1, $time2);
            $this->assertNotEquals($time2, $time3);
        })
        ;
    }

public function test_lazy_requests_can_be_bundled_with_attribute_parameter()
    {
        Livewire::visit([new class extends Component {
            public function render() { return <<<HTML
            <div>
                <livewire:child num="1" />
                <livewire:child num="2" />
                <livewire:child num="3" />
            </div>
            HTML; }
        }, 'child' => new #[\Livewire\Attributes\Lazy(isolate: false)] class extends Component {
            public $num;
            public $time;
            public function mount() {
                $this->time = LARAVEL_START;
            }
            public function render() { return <<<'HTML'
            <div id="child">
                Child {{ $num }}

                <span dusk="time-{{ $num }}">{{ $time }}</span>
            </div>
            HTML; }
        }])
        ->waitForText('Child 1')
        ->waitForText('Child 2')
        ->waitForText('Child 3')
        ->tap(function ($b) {
            $time1 = (float) $b->text('@time-1');
            $time2 = (float) $b->text('@time-2');
            $time3 = (float) $b->text('@time-3');

            $this->assertEquals($time1, $time2);
            $this->assertEquals($time2, $time3);
        })
        ;
    }
